/**  The lifecycle status of an MCP server connection. */
export type McpServerStatus =
  /**  The server is stopped and not connected. */
  | "stopped"
  /**  The server is starting up (launching process or connecting). */
  | "starting"
  /**  The server is running and ready to accept requests. */
  | "running"
  /**  The server has failed and is no longer running. */
  | "failed";

export type MemoryScope = "User" | "Workspace" | "Session";

/**  Why a background monitor process was stopped. */
export type MonitorStopReason =
  | { type: "ExitCode"; code: number }
  | { type: "Timeout" }
  | { type: "UserStopped" }
  | { type: "SessionEnded" };

export type PrivacyClassification = "minimal_trace" | "full_trace";

/**  A single MCP server entry returned by the catalog. */
export type ServerEntry = {
  id: string;
  source: string;
  display_name: string;
  summary: string;
  description: string;
  categories: string[];
  tags: string[];
  author: string | null;
  homepage: string | null;
  version: string | null;
  /**  Lower-case trust level: "unverified" | "community" | "verified". */
  trust: string;
  verified: boolean;
  icon: string | null;
  /**  JSON-encoded `agent_mcp::catalog::InstallSpec`. */
  install_spec_json: string;
  /**  JSON-encoded `Vec<agent_mcp::catalog::RuntimeRequirement>`. */
  requirements_json: string;
  /**  JSON-encoded `Vec<agent_mcp::catalog::EnvVarSpec>`. */
  default_env_json: string;
};

/**  Reason a task failed, used for diagnostics and UI display. */
export type TaskFailureReason =
  | { type: "ModelError"; retries: number }
  | { type: "ToolExhausted"; tool_id: string; attempts: number; last_error: string }
  | { type: "PermissionDenied"; tool_id: string }
  | { type: "Cancelled" }
  | { type: "MaxIterations" };

/**  A snapshot of the entire task graph for a session. */
export type TaskGraphSnapshot = {
  tasks: TaskSnapshot[];
};

/**  A snapshot of a single task in the task graph. */
export type TaskSnapshot = {
  id: string;
  title: string;
  role: AgentRole;
  state: TaskState;
  dependencies: string[];
  error: string | null;
  retry_count: number;
  max_retries: number;
  assigned_agent_id: string | null;
  failure_reason: TaskFailureReason | null;
};

export type TaskState =
  | "Pending"
  | "Ready"
  | "Running"
  | "Blocked"
  | "Completed"
  | "Failed"
  | "Skipped"
  | "Cancelled";

/**  How a trajectory ended. */
export type TrajectoryOutcome = "success" | "failed" | "cancelled" | "in_progress";
